/// Wrapper that bridges a foreign Py object to the `OcrBackend` trait.
pub struct PyOcrBackendBridge {
    inner: Py<PyAny>,
    cached_name: String,
}

impl PyOcrBackendBridge {
    /// Create a new bridge wrapping a Python object.
    ///
    /// Validates that the Python object provides all required methods.
    pub fn new(python_obj: Py<PyAny>) -> PyResult<Self> {
        Python::attach(|py| {
            let obj = python_obj.bind(py);
            if !obj.hasattr("process_image").unwrap_or(false) {
                return Err(pyo3::exceptions::PyAttributeError::new_err(
                    "Python object missing required method: process_image",
                ));
            }
            if !obj.hasattr("supports_language").unwrap_or(false) {
                return Err(pyo3::exceptions::PyAttributeError::new_err(
                    "Python object missing required method: supports_language",
                ));
            }
            if !obj.hasattr("backend_type").unwrap_or(false) {
                return Err(pyo3::exceptions::PyAttributeError::new_err(
                    "Python object missing required method: backend_type",
                ));
            }
            let cached_name: String = obj
                .call_method0("name")
                .and_then(|v| v.extract())
                .unwrap_or_else(|_| "unknown".to_string());

            Ok(Self {
                inner: python_obj,
                cached_name,
            })
        })
    }
}

impl kreuzberg::plugins::Plugin for PyOcrBackendBridge {
    fn name(&self) -> &str {
        &self.cached_name
    }

    fn version(&self) -> String {
        Python::attach(|py| {
            self.inner
                .bind(py)
                .call_method0("version")
                .and_then(|v| v.extract::<String>())
                .unwrap_or_default()
        })
    }

    fn initialize(&self) -> std::result::Result<(), kreuzberg::KreuzbergError> {
        Python::attach(|py| {
            self.inner
                .bind(py)
                .call_method0("initialize")
                .map(|_| ())
                .map_err(|e| kreuzberg::KreuzbergError::Plugin {
                    message: format!("Plugin '{}' method 'initialize' failed: {}", self.cached_name, e),
                    plugin_name: self.cached_name.clone(),
                })
        })
    }

    fn shutdown(&self) -> std::result::Result<(), kreuzberg::KreuzbergError> {
        Python::attach(|py| {
            self.inner
                .bind(py)
                .call_method0("shutdown")
                .map(|_| ())
                .map_err(|e| kreuzberg::KreuzbergError::Plugin {
                    message: format!("Plugin '{}' method 'shutdown' failed: {}", self.cached_name, e),
                    plugin_name: self.cached_name.clone(),
                })
        })
    }
}

#[async_trait::async_trait]
impl kreuzberg::plugins::OcrBackend for PyOcrBackendBridge {
    async fn process_image(
        &self,
        image_bytes: &[u8],
        config: &kreuzberg::OcrConfig,
    ) -> std::result::Result<kreuzberg::ExtractionResult, kreuzberg::KreuzbergError> {
        let python_obj = Python::attach(|py| self.inner.clone_ref(py));
        let cached_name = self.cached_name.clone();
        let image_bytes = image_bytes.to_vec();
        let config_json = serde_json::to_string(config).unwrap_or_default();

        tokio::task::spawn_blocking(move || {
            Python::attach(|py| {
                let obj = python_obj.bind(py);
                let py_result = obj
                    .call_method1(
                        "process_image",
                        (pyo3::types::PyBytes::new(py, &image_bytes), config_json.as_str()),
                    )
                    .map_err(|e| kreuzberg::KreuzbergError::Plugin {
                        message: format!("Plugin '{}' method 'process_image' failed: {}", cached_name, e),
                        plugin_name: cached_name.clone(),
                    })?;
                let json_val: String = py
                    .import("json")
                    .and_then(|m| m.call_method1("dumps", (py_result,)))
                    .and_then(|v| v.extract())
                    .map_err(|e| kreuzberg::KreuzbergError::Plugin {
                        message: format!("Plugin '{}': JSON serialization failed: {}", cached_name, e),
                        plugin_name: cached_name.clone(),
                    })?;
                serde_json::from_str::<kreuzberg::ExtractionResult>(&json_val).map_err(|e| {
                    kreuzberg::KreuzbergError::Plugin {
                        message: format!("Plugin '{}': deserialization failed: {}", cached_name, e),
                        plugin_name: cached_name.clone(),
                    }
                })
            })
        })
        .await
        .map_err(|e| kreuzberg::KreuzbergError::Plugin {
            message: format!("spawn_blocking failed: {}", e),
            plugin_name: self.cached_name.clone(),
        })
        .flatten()
    }

    async fn process_image_file(
        &self,
        path: &std::path::Path,
        config: &kreuzberg::OcrConfig,
    ) -> std::result::Result<kreuzberg::ExtractionResult, kreuzberg::KreuzbergError> {
        let python_obj = Python::attach(|py| self.inner.clone_ref(py));
        let cached_name = self.cached_name.clone();
        let path_str = path.to_string_lossy().to_string();
        let config_json = serde_json::to_string(config).unwrap_or_default();

        tokio::task::spawn_blocking(move || {
            Python::attach(|py| {
                let obj = python_obj.bind(py);
                let py_result = obj
                    .call_method1("process_image_file", (path_str.as_str(), config_json.as_str()))
                    .map_err(|e| kreuzberg::KreuzbergError::Plugin {
                        message: format!("Plugin '{}' method 'process_image_file' failed: {}", cached_name, e),
                        plugin_name: cached_name.clone(),
                    })?;
                let json_val: String = py
                    .import("json")
                    .and_then(|m| m.call_method1("dumps", (py_result,)))
                    .and_then(|v| v.extract())
                    .map_err(|e| kreuzberg::KreuzbergError::Plugin {
                        message: format!("Plugin '{}': JSON serialization failed: {}", cached_name, e),
                        plugin_name: cached_name.clone(),
                    })?;
                serde_json::from_str::<kreuzberg::ExtractionResult>(&json_val).map_err(|e| {
                    kreuzberg::KreuzbergError::Plugin {
                        message: format!("Plugin '{}': deserialization failed: {}", cached_name, e),
                        plugin_name: cached_name.clone(),
                    }
                })
            })
        })
        .await
        .map_err(|e| kreuzberg::KreuzbergError::Plugin {
            message: format!("spawn_blocking failed: {}", e),
            plugin_name: self.cached_name.clone(),
        })
        .flatten()
    }

    fn supports_language(&self, lang: &str) -> bool {
        Python::attach(|py| {
            self.inner
                .bind(py)
                .call_method1("supports_language", (lang,))
                .and_then(|v| v.extract::<bool>())
                .unwrap_or_default()
        })
    }

    fn backend_type(&self) -> kreuzberg::plugins::OcrBackendType {
        Python::attach(|py| {
            self.inner
                .bind(py)
                .call_method0("backend_type")
                .and_then(|v| v.extract::<String>())
                .and_then(|s| {
                    serde_json::from_str::<kreuzberg::plugins::OcrBackendType>(&s)
                        .map_err(|e| pyo3::exceptions::PyRuntimeError::new_err(e.to_string()))
                })
                .unwrap_or_default()
        })
    }

    fn supported_languages(&self) -> Vec<String> {
        Python::attach(|py| {
            self.inner
                .bind(py)
                .call_method0("supported_languages")
                .and_then(|v| v.extract::<Vec<String>>())
                .unwrap_or_default()
        })
    }

    fn supports_table_detection(&self) -> bool {
        Python::attach(|py| {
            self.inner
                .bind(py)
                .call_method0("supports_table_detection")
                .and_then(|v| v.extract::<bool>())
                .unwrap_or_default()
        })
    }

    fn supports_document_processing(&self) -> bool {
        Python::attach(|py| {
            self.inner
                .bind(py)
                .call_method0("supports_document_processing")
                .and_then(|v| v.extract::<bool>())
                .unwrap_or_default()
        })
    }

    async fn process_document(
        &self,
        _path: &std::path::Path,
        _config: &kreuzberg::OcrConfig,
    ) -> std::result::Result<kreuzberg::ExtractionResult, kreuzberg::KreuzbergError> {
        let python_obj = Python::attach(|py| self.inner.clone_ref(py));
        let cached_name = self.cached_name.clone();
        let _path_str = _path.to_string_lossy().to_string();
        let _config_json = serde_json::to_string(_config).unwrap_or_default();

        tokio::task::spawn_blocking(move || {
            Python::attach(|py| {
                let obj = python_obj.bind(py);
                let py_result = obj
                    .call_method1("process_document", (_path_str.as_str(), _config_json.as_str()))
                    .map_err(|e| kreuzberg::KreuzbergError::Plugin {
                        message: format!("Plugin '{}' method 'process_document' failed: {}", cached_name, e),
                        plugin_name: cached_name.clone(),
                    })?;
                let json_val: String = py
                    .import("json")
                    .and_then(|m| m.call_method1("dumps", (py_result,)))
                    .and_then(|v| v.extract())
                    .map_err(|e| kreuzberg::KreuzbergError::Plugin {
                        message: format!("Plugin '{}': JSON serialization failed: {}", cached_name, e),
                        plugin_name: cached_name.clone(),
                    })?;
                serde_json::from_str::<kreuzberg::ExtractionResult>(&json_val).map_err(|e| {
                    kreuzberg::KreuzbergError::Plugin {
                        message: format!("Plugin '{}': deserialization failed: {}", cached_name, e),
                        plugin_name: cached_name.clone(),
                    }
                })
            })
        })
        .await
        .map_err(|e| kreuzberg::KreuzbergError::Plugin {
            message: format!("spawn_blocking failed: {}", e),
            plugin_name: self.cached_name.clone(),
        })
        .flatten()
    }
}

#[pyfunction]
pub fn register_ocr_backend(py: Python<'_>, backend: Py<PyAny>) -> PyResult<()> {
    let required_methods = ["process_image", "supports_language", "backend_type"];
    let obj = backend.bind(py);
    for method in &required_methods {
        if !obj.hasattr(*method)? {
            return Err(pyo3::exceptions::PyAttributeError::new_err(format!(
                "Backend missing required method: {}",
                method
            )));
        }
    }

    let wrapper = PyOcrBackendBridge::new(backend)?;
    let arc: Arc<dyn kreuzberg::plugins::OcrBackend> = Arc::new(wrapper);

    py.detach(|| {
        let registry = kreuzberg::plugins::registry::get_ocr_backend_registry();
        let mut registry = registry.write();
        registry
            .register(arc)
            .map_err(|e| pyo3::exceptions::PyRuntimeError::new_err(format!("Failed to register backend: {}", e)))
    })?;
    Ok(())
}

// Error types
pyo3::create_exception!(_kreuzberg, IoError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, ParsingError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, OcrError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, ValidationError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, CacheError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, ImageProcessingError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, SerializationError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, MissingDependencyError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, PluginError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, LockPoisonedError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, UnsupportedFormatError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, EmbeddingError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, KreuzbergTimeoutError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, CancelledError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, OtherError, pyo3::exceptions::PyException);
pyo3::create_exception!(_kreuzberg, KreuzbergError, pyo3::exceptions::PyException);

/// Convert a `kreuzberg::KreuzbergError` error to a Python exception.
fn kreuzberg_error_to_py_err(e: kreuzberg::KreuzbergError) -> pyo3::PyErr {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        kreuzberg::KreuzbergError::Io(..) => IoError::new_err(msg),
        kreuzberg::KreuzbergError::Parsing { .. } => ParsingError::new_err(msg),
        kreuzberg::KreuzbergError::Ocr { .. } => OcrError::new_err(msg),
        kreuzberg::KreuzbergError::Validation { .. } => ValidationError::new_err(msg),
        kreuzberg::KreuzbergError::Cache { .. } => CacheError::new_err(msg),
        kreuzberg::KreuzbergError::ImageProcessing { .. } => ImageProcessingError::new_err(msg),
        kreuzberg::KreuzbergError::Serialization { .. } => SerializationError::new_err(msg),
        kreuzberg::KreuzbergError::MissingDependency(..) => MissingDependencyError::new_err(msg),
        kreuzberg::KreuzbergError::Plugin { .. } => PluginError::new_err(msg),
        kreuzberg::KreuzbergError::LockPoisoned(..) => LockPoisonedError::new_err(msg),
        kreuzberg::KreuzbergError::UnsupportedFormat(..) => UnsupportedFormatError::new_err(msg),
        kreuzberg::KreuzbergError::Embedding { .. } => EmbeddingError::new_err(msg),
        kreuzberg::KreuzbergError::Timeout { .. } => KreuzbergTimeoutError::new_err(msg),
        kreuzberg::KreuzbergError::Cancelled => CancelledError::new_err(msg),
        kreuzberg::KreuzbergError::Other(..) => OtherError::new_err(msg),
        _ => KreuzbergError::new_err(msg),
    }
}

